171→export function ProductFilters() {
172→  const router = useRouter();
173→  const searchParams = useSearchParams();
174→  const [categories, setCategories] = useState<CategoryDto[]>([]);
175→
176→  const activeCategories = searchParams.get("category")
177→    ? (searchParams.get("category")?.split(",") ?? [])
178→    : [];
179→  const activeRating = searchParams.get("rating") ?? "";
180→  const priceMin = Number(searchParams.get("priceMin") ?? "0");
181→  const priceMax = Number(searchParams.get("priceMax") ?? String(MAX_PRICE));
182→  const priceRange: [number, number] = [priceMin, priceMax];
183→
184→  useEffect(() => {
185→    getCategories()
186→      .then(setCategories)
187→      .catch(() => {
188→        // Silently handle - filters will show without categories
189→      });
190→  }, []);
191→
192→  const updateParams = (updates: Record<string, string | null>) => {
193→    const params = new URLSearchParams(searchParams.toString());
194→    for (const [key, value] of Object.entries(updates)) {
195→      if (value) {
196→        params.set(key, value);
197→      } else {
198→        params.delete(key);
199→      }
200→    }
201→    router.replace(`?${params.toString()}`, { scroll: false });
202→  };
203→
204→  const handleCategoryToggle = (categoryId: string) => {
205→    const current = new Set(activeCategories);
206→    if (current.has(categoryId)) {
207→      current.delete(categoryId);
208→    } else {
209→      current.add(categoryId);
210→    }
211→    const value = Array.from(current).join(",");
212→    updateParams({ category: value || null });
213→  };
214→
215→  const handlePriceChange = (value: number[]) => {
216→    updateParams({
217→      priceMin: value[0] === 0 ? null : String(value[0]),
218→      priceMax: value[1] === MAX_PRICE ? null : String(value[1]),
219→    });
220→  };
221→
222→  const handleRatingChange = (value: string) => {
223→    updateParams({
224→      rating: activeRating === value ? null : value,
225→    });
226→  };
227→
228→  const handleReset = () => {
229→    updateParams({
230→      category: null,
231→      priceMin: null,
232→      priceMax: null,
233→      rating: null,
234→    });
235→  };
236→
237→  const hasActiveFilters =
238→    activeCategories.length > 0 ||
239→    priceMin > 0 ||
240→    priceMax < MAX_PRICE ||
241→    activeRating !== "";
242→
243→  const filterProps = {
244→    categories,
245→    activeCategories,
246→    priceRange,
247→    activeRating,
248→    onCategoryToggle: handleCategoryToggle,
249→    onPriceChange: handlePriceChange,
250→    onRatingChange: handleRatingChange,
251→    onReset: handleReset,
252→    hasActiveFilters,
253→  };
254→
255→  return (
256→    <>
257→      {/* Desktop sidebar - hidden on mobile */}
258→      <aside className="hidden w-[260px] shrink-0 lg:block">
259→        <FilterContent {...filterProps} />
260→      </aside>
261→
262→      {/* Mobile filter Sheet trigger */}
263→      <div className="lg:hidden">
264→        <Sheet>
265→          <SheetTrigger asChild>
266→            <Button variant="outline" size="sm">
267→              <Filter className="size-4" />
268→              Filters
269→              {hasActiveFilters && (
270→                <span className="ml-1 flex size-5 items-center justify-center rounded-full bg-primary text-xs text-primary-foreground">
271→                  {activeCategories.length +
272→                    (priceMin > 0 || priceMax < MAX_PRICE ? 1 : 0) +
273→                    (activeRating ? 1 : 0)}
274→                </span>
275→              )}
276→            </Button>
277→          </SheetTrigger>
278→          <SheetContent side="left" className="overflow-y-auto">
279→            <SheetHeader>
280→              <SheetTitle>Filters</SheetTitle>
281→            </SheetHeader>
282→            <div className="px-4 pb-4">
283→              <FilterContent {...filterProps} />
284→            </div>
285→          </SheetContent>
286→        </Sheet>
287→      </div>
288→    </>
289→  );
290→}
