 45→interface PageItem {
 46→  type: "page" | "ellipsis";
 47→  value: number;
 48→  key: string;
 49→}
 50→
 51→function generatePageNumbers(
 52→  currentPage: number,
 53→  totalPages: number,
 54→): PageItem[] {
 55→  if (totalPages <= 5) {
 56→    return Array.from({ length: totalPages }, (_, i) => ({
 57→      type: "page" as const,
 58→      value: i + 1,
 59→      key: `page-${i + 1}`,
 60→    }));
 61→  }
 62→
 63→  const pages: PageItem[] = [{ type: "page", value: 1, key: "page-1" }];
 64→
 65→  if (currentPage > 3) {
 66→    pages.push({ type: "ellipsis", value: 0, key: "ellipsis-start" });
 67→  }
 68→
 69→  const start = Math.max(2, currentPage - 1);
 70→  const end = Math.min(totalPages - 1, currentPage + 1);
 71→
 72→  for (let i = start; i <= end; i++) {
 73→    pages.push({ type: "page", value: i, key: `page-${i}` });
 74→  }
 75→
 76→  if (currentPage < totalPages - 2) {
 77→    pages.push({ type: "ellipsis", value: 0, key: "ellipsis-end" });
 78→  }
 79→
 80→  pages.push({
 81→    type: "page",
 82→    value: totalPages,
 83→    key: `page-${totalPages}`,
 84→  });
 85→
 86→  return pages;
 87→}
