 89→export function ProductGrid({
 90→  categoryId,
 91→  search,
 92→  sortBy,
 93→  sortDirection,
 94→}: ProductGridProps) {
 95→  const router = useRouter();
 96→  const searchParams = useSearchParams();
 97→  const [products, setProducts] = useState<ProductDto[]>([]);
 98→  const [stockMap, setStockMap] = useState<Map<string, StockInfoDto>>(
 99→    new Map(),
100→  );
101→  const [totalCount, setTotalCount] = useState(0);
102→  const [loading, setLoading] = useState(true);
103→
104→  const currentPage = Number(searchParams.get("page") ?? "1");
105→  const currentSort = searchParams.get("sort") ?? "featured";
106→  const totalPages = Math.max(1, Math.ceil(totalCount / PAGE_SIZE));
107→
108→  // Track filter changes to reset page
109→  const filtersRef = useRef({ categoryId, search, sortBy, sortDirection });
110→
111→  // Reset page when filters change
112→  useEffect(() => {
113→    const prev = filtersRef.current;
114→    const filtersChanged =
115→      prev.categoryId !== categoryId ||
116→      prev.search !== search ||
117→      prev.sortBy !== sortBy ||
118→      prev.sortDirection !== sortDirection;
119→
120→    if (filtersChanged) {
121→      filtersRef.current = { categoryId, search, sortBy, sortDirection };
122→    }
123→  }, [categoryId, search, sortBy, sortDirection]);
124→
125→  // Fetch stock levels for a batch of products and merge into stockMap
126→  const fetchStockForProducts = useCallback(
127→    async (productItems: ProductDto[]) => {
128→      if (productItems.length === 0) return;
129→      try {
130→        const productIds = productItems.map((p) => p.id);
131→        const stockLevels = await getStockLevels(productIds);
132→        setStockMap((prev) => {
133→          const next = new Map(prev);
134→          for (const stock of stockLevels) {
135→            next.set(stock.productId, stock);
136→          }
137→          return next;
138→        });
139→      } catch {
140→        // Stock fetch failure is non-critical - cards render without stock badges
141→      }
142→    },
143→    [],
144→  );
145→
146→  // Fetch products for current page
147→  useEffect(() => {
148→    let cancelled = false;
149→
150→    async function load() {
151→      setLoading(true);
152→      try {
153→        const data = await getStorefrontProducts({
154→          page: currentPage,
155→          pageSize: PAGE_SIZE,
156→          categoryId,
157→          search,
158→          sortBy,
159→          sortDirection,
160→        });
161→
162→        if (!cancelled) {
163→          setProducts(data.items);
164→          setTotalCount(data.totalCount);
165→          fetchStockForProducts(data.items);
166→        }
167→      } catch {
168→        // Silently handle error - products stay as-is
169→      } finally {
170→        if (!cancelled) {
171→          setLoading(false);
172→        }
173→      }
174→    }
175→
176→    load();
177→    return () => {
178→      cancelled = true;
179→    };
180→  }, [
181→    currentPage,
182→    categoryId,
183→    search,
184→    sortBy,
185→    sortDirection,
186→    fetchStockForProducts,
187→  ]);
188→
189→  const updateSearchParam = (key: string, value: string | null) => {
190→    const params = new URLSearchParams(searchParams.toString());
191→    if (value) {
192→      params.set(key, value);
193→    } else {
194→      params.delete(key);
195→    }
196→    router.replace(`?${params.toString()}`, { scroll: false });
197→  };
198→
199→  const handleSortChange = (value: string) => {
200→    const params = new URLSearchParams(searchParams.toString());
201→    if (value === "featured") {
202→      params.delete("sort");
203→    } else {
204→      params.set("sort", value);
205→    }
206→    params.delete("page");
207→    router.replace(`?${params.toString()}`, { scroll: false });
208→  };
209→
210→  const handlePageChange = (page: number) => {
211→    if (page === 1) {
212→      updateSearchParam("page", null);
213→    } else {
214→      updateSearchParam("page", String(page));
215→    }
216→    window.scrollTo({ top: 0, behavior: "smooth" });
217→  };
218→
219→  const startItem = (currentPage - 1) * PAGE_SIZE + 1;
220→  const endItem = Math.min(currentPage * PAGE_SIZE, totalCount);
221→
222→  // Initial loading state
223→  if (loading && products.length === 0) {
224→    return (
225→      <div className="flex flex-col gap-6">
226→        <div className="flex items-center justify-between">
227→          <div className="h-5 w-48 animate-pulse rounded bg-muted" />
228→          <div className="h-9 w-40 animate-pulse rounded-md bg-muted" />
229→        </div>
230→        <div className="grid grid-cols-1 gap-5 sm:grid-cols-2 lg:grid-cols-3">
231→          {Array.from({ length: 6 }, (_, i) => `skeleton-${i}`).map((key) => (
232→            <ProductCardSkeleton key={key} />
233→          ))}
234→        </div>
235→      </div>
236→    );
237→  }
238→
239→  // Empty state
240→  if (!loading && products.length === 0) {
