 5→interface StarRatingDisplayProps {
 6→  rating: number;
 7→  count?: number;
 8→  showCount?: boolean;
 9→  size?: "sm" | "md";
10→}
11→
12→export function StarRatingDisplay({
13→  rating,
14→  count,
15→  showCount = false,
16→  size = "md",
17→}: StarRatingDisplayProps) {
18→  const stars = [];
19→  const fullStars = Math.floor(rating);
20→  const hasHalfStar = rating % 1 >= 0.5;
21→  const iconSize = size === "sm" ? "size-3.5" : "size-4";
22→
23→  for (let i = 1; i <= 5; i++) {
24→    if (i <= fullStars) {
25→      // Full star
26→      stars.push(
27→        <Star key={i} className={`${iconSize} fill-star text-star`} />,
28→      );
29→    } else if (i === fullStars + 1 && hasHalfStar) {
30→      // Half star (approximated with lighter fill)
31→      stars.push(
32→        <Star key={i} className={`${iconSize} fill-star/50 text-star`} />,
33→      );
34→    } else {
35→      // Empty star
36→      stars.push(<Star key={i} className={`${iconSize} text-border`} />);
37→    }
38→  }
39→
40→  return (
41→    <div className="flex items-center gap-1.5">
42→      <div className="flex items-center gap-0.5">{stars}</div>
43→      {showCount && count !== undefined && (
44→        <span className="text-sm text-muted-foreground">
45→          {rating.toFixed(1)} ({count} {count === 1 ? "review" : "reviews"})
46→        </span>
47→      )}
48→    </div>
49→  );
50→}
