  3→import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
  4→import { toast } from "sonner";
  5→
  6→import {
  7→  type AddToCartRequest,
  8→  type CartDto,
  9→  addToCart,
 10→  getCart,
 11→  removeCartItem,
 12→  updateCartItemQuantity,
 13→} from "@/lib/api";
 14→
 15→const CART_QUERY_KEY = ["cart"] as const;
 16→
 17→export function useCart() {
 18→  return useQuery({
 19→    queryKey: CART_QUERY_KEY,
 20→    queryFn: getCart,
 21→  });
 22→}
 23→
 24→export function useCartItemCount() {
 25→  return useQuery({
 26→    queryKey: CART_QUERY_KEY,
 27→    queryFn: getCart,
 28→    select: (data) =>
 29→      data?.items.reduce((sum, item) => sum + item.quantity, 0) ?? 0,
 30→  });
 31→}
 32→
 33→export function useAddToCart() {
 34→  const queryClient = useQueryClient();
 35→
 36→  return useMutation({
 37→    mutationFn: (data: AddToCartRequest) => addToCart(data),
 38→    onSuccess: (response) => {
 39→      queryClient.invalidateQueries({ queryKey: CART_QUERY_KEY });
 40→      toast.success(response.isUpdate ? "Updated quantity" : "Added to cart");
 41→    },
 42→    onError: () => {
 43→      toast.error("Failed to add to cart");
 44→    },
 45→  });
 46→}
 47→
 48→export function useUpdateCartItem() {
 49→  const queryClient = useQueryClient();
 50→
 51→  return useMutation({
 52→    mutationFn: ({ itemId, quantity }: { itemId: string; quantity: number }) =>
 53→      updateCartItemQuantity(itemId, quantity),
 54→    onMutate: async ({ itemId, quantity }) => {
 55→      await queryClient.cancelQueries({ queryKey: CART_QUERY_KEY });
 56→
 57→      const previousCart = queryClient.getQueryData<CartDto | null>(
 58→        CART_QUERY_KEY
 59→      );
 60→
 61→      queryClient.setQueryData<CartDto | null>(CART_QUERY_KEY, (old) => {
 62→        if (!old) return old;
 63→        return {
 64→          ...old,
 65→          items: old.items.map((item) =>
 66→            item.id === itemId
 67→              ? {
 68→                  ...item,
 69→                  quantity,
 70→                  lineTotal: item.unitPrice * quantity,
 71→                }
 72→              : item
 73→          ),
 74→          totalPrice: old.items.reduce(
 75→            (sum, item) =>
 76→              sum +
 77→              (item.id === itemId
 78→                ? item.unitPrice * quantity
 79→                : item.lineTotal),
 80→            0
 81→          ),
 82→          totalItems: old.items.reduce(
 83→            (sum, item) =>
 84→              sum + (item.id === itemId ? quantity : item.quantity),
 85→            0
 86→          ),
 87→        };
 88→      });
 89→
 90→      return { previousCart };
 91→    },
 92→    onError: (_err, _vars, context) => {
 93→      if (context?.previousCart !== undefined) {
 94→        queryClient.setQueryData(CART_QUERY_KEY, context.previousCart);
 95→      }
 96→      toast.error("Failed to update quantity");
 97→    },
 98→    onSettled: () => {
 99→      queryClient.invalidateQueries({ queryKey: CART_QUERY_KEY });
100→    },
101→  });
102→}
103→
104→export function useRemoveCartItem() {
105→  const queryClient = useQueryClient();
106→
107→  return useMutation({
108→    mutationFn: (itemId: string) => removeCartItem(itemId),
109→    onMutate: async (itemId) => {
110→      await queryClient.cancelQueries({ queryKey: CART_QUERY_KEY });
111→
112→      const previousCart = queryClient.getQueryData<CartDto | null>(
113→        CART_QUERY_KEY
114→      );
115→
116→      queryClient.setQueryData<CartDto | null>(CART_QUERY_KEY, (old) => {
117→        if (!old) return old;
118→        const removedItem = old.items.find((item) => item.id === itemId);
119→        const filteredItems = old.items.filter((item) => item.id !== itemId);
120→        return {
121→          ...old,
122→          items: filteredItems,
123→          totalPrice: old.totalPrice - (removedItem?.lineTotal ?? 0),
124→          totalItems: old.totalItems - (removedItem?.quantity ?? 0),
125→        };
126→      });
127→
128→      return { previousCart };
129→    },
130→    onError: (_err, _vars, context) => {
131→      if (context?.previousCart !== undefined) {
132→        queryClient.setQueryData(CART_QUERY_KEY, context.previousCart);
133→      }
134→      toast.error("Failed to remove item");
135→    },
136→    onSettled: () => {
137→      queryClient.invalidateQueries({ queryKey: CART_QUERY_KEY });
138→    },
139→  });
140→}
