 20→function formatPrice(price: number, currency: string): string {
 21→  return new Intl.NumberFormat("en-US", {
 22→    style: "currency",
 23→    currency,
 24→  }).format(price);
 25→}
 26→
 27→function StockBadge({ stockInfo }: { stockInfo?: StockInfoDto }) {
 28→  if (!stockInfo) return null;
 29→
 30→  const { availableQuantity } = stockInfo;
 31→
 32→  if (availableQuantity === 0) {
 33→    return (
 34→      <Badge variant="destructive" className="text-[10px] font-semibold">
 35→        Out of Stock
 36→      </Badge>
 37→    );
 38→  }
 39→
 40→  if (availableQuantity <= 10) {
 41→    return (
 42→      <Badge className="bg-warning-bg text-[10px] font-semibold text-warning-foreground hover:bg-warning-bg">
 43→        Only {availableQuantity} left!
 44→      </Badge>
 45→    );
 46→  }
 47→
 48→  return (
 49→    <Badge className="bg-success-bg text-[10px] font-semibold text-success-foreground hover:bg-success-bg">
 50→      <CheckCircle className="mr-0.5 size-3" />
 51→      In Stock
 52→    </Badge>
 53→  );
 54→}
 55→
 56→export function ProductCard({ product, stockInfo }: ProductCardProps) {
 57→  const isOutOfStock = stockInfo ? stockInfo.availableQuantity === 0 : false;
 58→  const addToCart = useAddToCart();
 59→
 60→  return (
 61→    <Link href={`/products/${product.id}`} className="group block">
 62→      <Card
 63→        className={`overflow-hidden border-border py-0 transition-shadow duration-300 group-hover:shadow-md ${
 64→          isOutOfStock ? "opacity-60" : ""
 65→        }`}
 66→      >
 67→        {/* Image area */}
 68→        <div className="relative aspect-[4/3] overflow-hidden bg-muted">
 69→          {product.imageUrl ? (
