 75→              className={`object-cover transition-transform duration-500 group-hover:scale-105 ${
 76→                isOutOfStock ? "grayscale" : ""
 77→              }`}
 78→            />
 79→          ) : (
 80→            <div className="flex h-full items-center justify-center">
 81→              <ShoppingCart className="size-12 text-border" />
 82→            </div>
 83→          )}
 84→
 85→          {/* Wishlist heart - top left of image */}
 86→          <div className="absolute left-2 top-2 z-10">
 87→            <WishlistToggleButton productId={product.id} />
 88→          </div>
 89→
 90→          {/* Stock badge - top right of image */}
 91→          {stockInfo && (
 92→            <div className="absolute right-2 top-2">
 93→              <StockBadge stockInfo={stockInfo} />
 94→            </div>
 95→          )}
 96→
 97→          {/* Out of stock overlay */}
 98→          {isOutOfStock && (
 99→            <div className="absolute inset-0 bg-background/30" />
100→          )}
101→
102→          {/* Hover overlay with Add to Cart */}
103→          {!isOutOfStock && (
104→            <div className="absolute inset-0 flex items-end justify-center bg-black/0 pb-4 opacity-0 transition-all duration-300 group-hover:bg-black/20 group-hover:opacity-100">
105→              <Button
106→                size="sm"
107→                className="translate-y-2 rounded-full transition-transform duration-300 group-hover:translate-y-0"
108→                onClick={(e) => {
109→                  e.preventDefault();
110→                  e.stopPropagation();
111→                  addToCart.mutate({
112→                    productId: product.id,
113→                    productName: product.name,
114→                    unitPrice: product.price,
115→                    imageUrl: product.imageUrl,
116→                    quantity: 1,
117→                  });
118→                }}
119→                disabled={addToCart.isPending}
120→              >
121→                <ShoppingCart className="mr-1 size-4" />
122→                Add to Cart
123→              </Button>
124→            </div>
125→          )}
126→        </div>
127→
128→        {/* Product info */}
129→        <CardContent className="flex flex-col gap-2 p-4">
130→          <h3 className="line-clamp-2 text-sm font-semibold text-foreground">
131→            {product.name}
132→          </h3>
133→
134→          <div className="flex items-center justify-between">
135→            <p className="text-base font-bold text-foreground">
136→              {formatPrice(product.price, product.priceCurrency)}
137→            </p>
138→            <Heart className="size-[18px] text-muted-foreground" />
139→          </div>
140→
141→          {product.reviewCount > 0 && product.averageRating !== null && (
142→            <StarRatingDisplay
143→              rating={product.averageRating}
144→              count={product.reviewCount}
145→              size="sm"
146→            />
147→          )}
148→
149→          <Button
150→            className="mt-1 w-full"
151→            onClick={(e) => {
152→              e.preventDefault();
153→              e.stopPropagation();
154→              addToCart.mutate({
155→                productId: product.id,
156→                productName: product.name,
157→                unitPrice: product.price,
158→                imageUrl: product.imageUrl,
159→                quantity: 1,
160→              });
161→            }}
162→            disabled={isOutOfStock || addToCart.isPending}
